// 1. Verificar Signing Secret de Slack
// 2. Parsear payload de interactividad
const body = $input.first().json.body;
const headers = $input.first().json.headers;

// En producción: verificar firma HMAC con el Signing Secret
// const signingSecret = $vars.OPEX_SLACK_SIGNING_SECRET;
// const timestamp = headers['x-slack-request-timestamp'];
// const slackSig = headers['x-slack-signature'];
// const baseString = `v0:${timestamp}:${rawBody}`;
// const computed = 'v0=' + crypto.createHmac('sha256', signingSecret).update(baseString).digest('hex');
// if (computed !== slackSig) throw new Error('Slack signature mismatch');

// Parsear el payload (viene como form-urlencoded)
let payload;
try {
  payload = typeof body.payload === 'string' ? JSON.parse(body.payload) : body.payload;
} catch(e) {
  throw new Error('Payload Slack inválido: ' + e.message);
}

const action = payload.actions?.[0];
const actionId = action?.action_id || '';
const actionValue = action?.value || '';
const userId = payload.user?.id || 'desconocido';
const userName = payload.user?.username || 'desconocido';
const messageTs = payload.message?.ts || '';
const channelId = payload.channel?.id || '';

// Determinar tipo de acción
let tipoAccion = 'desconocida';
if (actionId === 'aprobar_comunicacion' || actionId.startsWith('aprobar_')) tipoAccion = 'aprobar';
else if (actionId === 'rechazar_comunicacion' || actionId.startsWith('rechazar_')) tipoAccion = 'rechazar';
else if (actionId === 'falso_positivo' || actionId.startsWith('fp_')) tipoAccion = 'false_positive';
else if (actionId === 'pausar_alertas') tipoAccion = 'pausar';
else if (actionId === 'ver_cola_aprobacion') tipoAccion = 'ver_cola';
else if (actionId === 'recalibrar_aplicar') tipoAccion = 'recalibrar_aplicar';
else if (actionId === 'recalibrar_ignorar') tipoAccion = 'recalibrar_ignorar';

// Extraer ID de la alerta/aprobación del value o action_id
const idEntidad = actionValue.replace(/^(aprobar_|rechazar_|fp_)/, '') || actionValue;

return [{
  json: {
    tipo_accion: tipoAccion,
    action_id: actionId,
    id_entidad: idEntidad,
    user_id: userId,
    user_name: userName,
    message_ts: messageTs,
    channel_id: channelId,
    payload_completo: payload
  }
}];

// Cerrar alerta como false_positive y crear case
const data = $input.first().json;
const parsedData = $('Parsear y Validar Payload Slack').first().json;

return [{
  json: {
    alert_id: parsedData.id_entidad,
    user_name: parsedData.user_name,
    veredicto: 'false_positive',
    causa_raiz_texto: 'Marcado como falso positivo desde Slack',
    canal_cierre: 'slack',
    cerrado_en: new Date().toISOString()
  }
}];
